package com.example.api.service;

import com.example.api.model.Item;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.time.LocalDateTime;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;

@Service
public class ItemService {

    private static final Logger logger = LoggerFactory.getLogger(ItemService.class);

    private final Map<Long, Item> itemStore = new ConcurrentHashMap<>();
    private final AtomicLong idGenerator = new AtomicLong(1);

    public ItemService() {
        logger.info("Initializing ItemService with sample data");
        createItem(new Item(null, "Laptop", "High-performance laptop", 999.99));
        createItem(new Item(null, "Keyboard", "Mechanical keyboard", 149.99));
        createItem(new Item(null, "Mouse", "Wireless mouse", 49.99));
        logger.info("ItemService initialized with {} sample items", itemStore.size());
    }

    public List<Item> getAllItems() {
        logger.info("Retrieving all items from store");
        List<Item> items = new ArrayList<>(itemStore.values());
        logger.info("Retrieved {} items successfully", items.size());
        return items;
    }

    public Optional<Item> getItemById(Long id) {
        logger.info("Retrieving item with id={}", id);
        Optional<Item> item = Optional.ofNullable(itemStore.get(id));
        if (item.isPresent()) {
            logger.info("Item found: {}", item.get());
        } else {
            logger.warn("Item with id={} not found", id);
        }
        return item;
    }

    public Item createItem(Item item) {
        Long id = idGenerator.getAndIncrement();
        item.setId(id);
        item.setCreatedAt(LocalDateTime.now());
        item.setUpdatedAt(LocalDateTime.now());
        itemStore.put(id, item);
        logger.info("Created new item: {}", item);
        return item;
    }

    public Optional<Item> updateItem(Long id, Item updatedItem) {
        logger.info("Updating item with id={}", id);
        Item existingItem = itemStore.get(id);
        if (existingItem == null) {
            logger.warn("Cannot update item with id={}: not found", id);
            return Optional.empty();
        }
        existingItem.setName(updatedItem.getName());
        existingItem.setDescription(updatedItem.getDescription());
        existingItem.setPrice(updatedItem.getPrice());
        existingItem.setUpdatedAt(LocalDateTime.now());
        itemStore.put(id, existingItem);
        logger.info("Updated item successfully: {}", existingItem);
        return Optional.of(existingItem);
    }

    public boolean deleteItem(Long id) {
        logger.info("Deleting item with id={}", id);
        Item removed = itemStore.remove(id);
        if (removed != null) {
            logger.info("Deleted item successfully: {}", removed);
            return true;
        } else {
            logger.warn("Cannot delete item with id={}: not found", id);
            return false;
        }
    }

    public List<Item> searchItems(String query) {
        logger.info("Searching items with query='{}'", query);
        List<Item> results = itemStore.values().stream()
                .filter(item -> item.getName().toLowerCase().contains(query.toLowerCase())
                        || item.getDescription().toLowerCase().contains(query.toLowerCase()))
                .toList();
        logger.info("Search completed: found {} items matching query='{}'", results.size(), query);
        return results;
    }
}

