package com.example.api.controller;

import com.example.api.model.ApiResponse;
import com.example.api.model.Item;
import com.example.api.service.ItemService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.List;
import java.util.Optional;

@RestController
@RequestMapping("/api/items")
public class ItemController {

    private static final Logger logger = LoggerFactory.getLogger(ItemController.class);

    private final ItemService itemService;

    public ItemController(ItemService itemService) {
        this.itemService = itemService;
        logger.info("ItemController initialized");
    }

    @GetMapping
    public ResponseEntity<ApiResponse<List<Item>>> getAllItems() {
        logger.info("GET /api/items - Fetching all items");
        List<Item> items = itemService.getAllItems();
        logger.info("GET /api/items - Returning {} items", items.size());
        return ResponseEntity.ok(new ApiResponse<>(true, "Items retrieved successfully", items));
    }

    @GetMapping("/{id}")
    public ResponseEntity<ApiResponse<Item>> getItemById(@PathVariable Long id) {
        logger.info("GET /api/items/{} - Fetching item by id", id);
        Optional<Item> item = itemService.getItemById(id);
        if (item.isPresent()) {
            logger.info("GET /api/items/{} - Item found", id);
            return ResponseEntity.ok(new ApiResponse<>(true, "Item retrieved successfully", item.get()));
        } else {
            logger.warn("GET /api/items/{} - Item not found", id);
            return ResponseEntity.status(HttpStatus.NOT_FOUND)
                    .body(new ApiResponse<>(false, "Item not found with id: " + id, null));
        }
    }

    @PostMapping
    public ResponseEntity<ApiResponse<Item>> createItem(@RequestBody Item item) {
        logger.info("POST /api/items - Creating new item with name='{}'", item.getName());
        Item createdItem = itemService.createItem(item);
        logger.info("POST /api/items - Item created with id={}", createdItem.getId());
        return ResponseEntity.status(HttpStatus.CREATED)
                .body(new ApiResponse<>(true, "Item created successfully", createdItem));
    }

    @PutMapping("/{id}")
    public ResponseEntity<ApiResponse<Item>> updateItem(@PathVariable Long id, @RequestBody Item item) {
        logger.info("PUT /api/items/{} - Updating item", id);
        Optional<Item> updatedItem = itemService.updateItem(id, item);
        if (updatedItem.isPresent()) {
            logger.info("PUT /api/items/{} - Item updated successfully", id);
            return ResponseEntity.ok(new ApiResponse<>(true, "Item updated successfully", updatedItem.get()));
        } else {
            logger.warn("PUT /api/items/{} - Item not found for update", id);
            return ResponseEntity.status(HttpStatus.NOT_FOUND)
                    .body(new ApiResponse<>(false, "Item not found with id: " + id, null));
        }
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<ApiResponse<Void>> deleteItem(@PathVariable Long id) {
        logger.info("DELETE /api/items/{} - Deleting item", id);
        boolean deleted = itemService.deleteItem(id);
        if (deleted) {
            logger.info("DELETE /api/items/{} - Item deleted successfully", id);
            return ResponseEntity.ok(new ApiResponse<>(true, "Item deleted successfully", null));
        } else {
            logger.warn("DELETE /api/items/{} - Item not found for deletion", id);
            return ResponseEntity.status(HttpStatus.NOT_FOUND)
                    .body(new ApiResponse<>(false, "Item not found with id: " + id, null));
        }
    }

    @GetMapping("/search")
    public ResponseEntity<ApiResponse<List<Item>>> searchItems(@RequestParam String query) {
        logger.info("GET /api/items/search?query='{}' - Searching items", query);
        List<Item> results = itemService.searchItems(query);
        logger.info("GET /api/items/search - Found {} results for query='{}'", results.size(), query);
        return ResponseEntity.ok(new ApiResponse<>(true, "Search completed successfully", results));
    }
}

